bash_commands.command:
cat > /tmp/refactor2.sh << 'EOREFACTOR'
#!/bin/bash
set -e

cd /workspace

echo "Starting refactoring..."

# Phase 1: Update all imports and class name references in ALL files
echo "Phase 1: Updating all class name references..."

# FxVanillaOption -> FxEuropeanOption
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOption\b/FxEuropeanOption/g' {} \;
echo "FxVanillaOption -> FxEuropeanOption replacements done"

# FxVanillaOptionTrade -> FxEuropeanOptionTrade
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionTrade\b/FxEuropeanOptionTrade/g' {} \;
echo "FxVanillaOptionTrade -> FxEuropeanOptionTrade replacements done"

# ResolvedFxVanillaOption -> ResolvedFxEuropeanOption
find modules -name "*.java" -type f -exec sed -i 's/ResolvedFxVanillaOption\b/ResolvedFxEuropeanOption/g' {} \;
echo "ResolvedFxVanillaOption -> ResolvedFxEuropeanOption replacements done"

# ResolvedFxVanillaOptionTrade -> ResolvedFxEuropeanOptionTrade  
find modules -name "*.java" -type f -exec sed -i 's/ResolvedFxVanillaOptionTrade\b/ResolvedFxEuropeanOptionTrade/g' {} \;
echo "ResolvedFxVanillaOptionTrade -> ResolvedFxEuropeanOptionTrade replacements done"

# Pricer class renames
find modules -name "*.java" -type f -exec sed -i 's/BlackFxVanillaOptionProductPricer\b/BlackFxEuropeanOptionProductPricer/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/BlackFxVanillaOptionTradePricer\b/BlackFxEuropeanOptionTradePricer/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/VannaVolgaFxVanillaOptionProductPricer\b/VannaVolgaFxEuropeanOptionProductPricer/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/VannaVolgaFxVanillaOptionTradePricer\b/VannaVolgaFxEuropeanOptionTradePricer/g' {} \;
echo "Pricer class renames done"

# Measure class renames
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionMethod\b/FxEuropeanOptionMethod/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionMeasureCalculations\b/FxEuropeanOptionMeasureCalculations/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionTradeCalculationFunction\b/FxEuropeanOptionTradeCalculationFunction/g' {} \;
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionTradeCalculations\b/FxEuropeanOptionTradeCalculations/g' {} \;
echo "Measure class renames done"

# Loader plugin rename
find modules -name "*.java" -type f -exec sed -i 's/FxVanillaOptionTradeCsvPlugin\b/FxEuropeanOptionTradeCsvPlugin/g' {} \;
echo "Loader plugin rename done"

# Update ProductType constant
find modules -name "ProductType.java" -type f -exec sed -i 's/FX_VANILLA_OPTION/FX_EUROPEAN_OPTION/g' {} \;
find modules -name "ProductType.java" -type f -exec sed -i 's/"FxVanillaOption"/"FxEuropeanOption"/g' {} \;
find modules -name "ProductType.java" -type f -exec sed -i 's/"FX Vanilla Option"/"FX European Option"/g' {} \;
echo "ProductType constant updates done"

# CSV plugin string updates  
find modules -name "*CsvPlugin*.java" -o -name "TradeCsvInfoResolver.java" -o -name "CsvWriterUtils.java" | \
  xargs grep -l "FxEuropeanOption" | \
  xargs sed -i 's/"FxVanillaOption"/"FxEuropeanOption"/g'
find modules -name "*CsvPlugin*.java" -o -name "TradeCsvInfoResolver.java" -o -name "CsvWriterUtils.java" | \
  xargs grep -l "FxEuropeanOption" | \
  xargs sed -i 's/FXVANILLAOPTION/FXEUROPEANOPTION/g'
find modules -name "*CsvPlugin*.java" -o -name "TradeCsvInfoResolver.java" -o -name "CsvWriterUtils.java" | \
  xargs grep -l "FxEuropeanOption" | \
  xargs sed -i 's/FX VANILLA OPTION/FX EUROPEAN OPTION/g'
echo "CSV plugin string updates done"

echo "Phase 1 complete: All class name references updated"
EOREFACTOR

chmod +x /tmp/refactor2.sh
bash /tmp/refactor2.sh 2>&1 | tail -20

